// Physical component
instance MabiMax100Robot : DTDFVocab:Component [
    base:desc "Serial industrial robot MABI MAX 100, six‑axis with permanent‑magnet synchronous motors, gearboxes, high‑resolution encoders, controlled by Siemens SINUMERIK 840D sl controller."
]

// Sensing components
instance EncoderSensor : DTDFVocab:SensingComponent [
    base:desc "High‑resolution rotary encoder attached to each robot joint, providing precise joint angle measurements."
    DTDFVocab:producedData EncoderPositionDataTransmitted
]

instance ControllerLogSensor : DTDFVocab:SensingComponent [
    base:desc "SINUMERIK 840D sl controller log interface providing operational traces and status information."
    DTDFVocab:producedData ControllerLogDataTransmitted
]

// Data transmitted (physical‑to‑virtual)
instance EncoderPositionDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom EncoderSensor
]

instance ControllerLogDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom ControllerLogSensor
]

// Data (digital shadow)
instance EncoderPositionData : DTDFVocab:Data [
    base:desc "Aggregated joint position traces from encoder sensors, abstracted for modeling purposes."
    DTDFVocab:fromData EncoderPositionDataTransmitted
    DTDFVocab:inputTo SimulinkEngine, JointFrictionModelProcessor
]

instance ControllerLogData : DTDFVocab:Data [
    base:desc "Collected controller execution logs and status messages, used for state estimation and fault detection."
    DTDFVocab:fromData ControllerLogDataTransmitted
    DTDFVocab:inputTo JavaMLRuntime, StateMachineProcessor
]

// Models / Data resources
instance MechanicalDynamicsModel : DTDFVocab:Model [
    base:desc "White‑box multi‑physics Simulink model of robot dynamics including inertia, gear friction and thermal effects."
    DTDFVocab:inputTo SimulinkEngine
]

instance JointFrictionModel : DTDFVocab:Model [
    base:desc "Black‑box machine‑learning regressor estimating joint friction based on sensor data."
    DTDFVocab:inputTo JointFrictionModelProcessor
]

instance RobotStateMachineModel : DTDFVocab:Model [
    base:desc "SysML v1.7 state machine describing robot controller states and transitions."
    DTDFVocab:inputTo StateMachineProcessor
]

// Enablers (processing / execution environments)
instance SimulinkEngine : DTDFVocab:Enabler [
    base:desc "Simulink simulation engine executing white‑box dynamics models."
    DTDFVocab:enables SimulationService
]

instance JointFrictionModelProcessor : DTDFVocab:Enabler [
    base:desc "Java runtime executing black‑box friction estimation model."
    DTDFVocab:enables FrictionEstimationService
]

instance JavaMLRuntime : DTDFVocab:Enabler [
    base:desc "Java environment for running machine‑learning models on controller logs."
    DTDFVocab:enables PredictionService
]

instance StateMachineProcessor : DTDFVocab:Enabler [
    base:desc "C++ implementation of SysML state‑machine interpreter for runtime monitoring."
    DTDFVocab:enables MonitoringService
]

// Services offered by the Digital Twin
instance SimulationService : DTDFVocab:Service [
    base:desc "Provides high‑fidelity simulation results of robot dynamics for analysis."
    DTDFVocab:provides HighFidelitySimulationInsight
]

instance FrictionEstimationService : DTDFVocab:Service [
    base:desc "Computes friction estimates from sensor traces to improve control accuracy."
    DTDFVocab:provides FrictionEstimateInsight
]

instance PredictionService : DTDFVocab:Service [
    base:desc "Predicts future robot states based on controller logs and learned models."
    DTDFVocab:provides PredictiveStateInsight
]

instance MonitoringService : DTDFVocab:Service [
    base:desc "Monitors robot operational state and raises alerts."
    DTDFVocab:provides OperationalAnomalyInsight
]

instance ControlAdjustmentService : DTDFVocab:Service [
    base:desc "Generates recommended control‑parameter adjustments based on friction estimates."
    DTDFVocab:provides ControlParameterAdjustmentAction
]

// Insights and actions derived from the Twin
instance HighFidelitySimulationInsight : DTDFVocab:Insight [
    base:desc "Detailed simulation output enabling performance evaluation of robot trajectories."
]

instance FrictionEstimateInsight : DTDFVocab:Insight [
    base:desc "Estimated joint friction values used to calibrate controller gains."
]

instance PredictiveStateInsight : DTDFVocab:Insight [
    base:desc "Predicted future joint positions and velocities for proactive planning."
]

instance OperationalAnomalyInsight : DTDFVocab:Insight [
    base:desc "Detected anomalies in controller behavior indicating potential faults."
]

instance ControlParameterAdjustmentAction : DTDFVocab:Action [
    base:desc "Operator or automated action to adjust controller PID parameters based on friction estimates."
    DTDFVocab:IsAutomatic false
]

// Environment containing the robot
instance IndustrialCellEnvironment : DTDFVocab:Environment [
    base:contains MabiMax100Robot
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The system follows the Digital Shadow Reference Model (Fig. 1) and its concrete realisation (Fig. 5), forming a pipeline that orchestrates the dynamic exchange of friction models. Core components include: data‑trace acquisition, Processing components that execute data‑calculation or simulation models, and model repositories. The architecture adopts a modular, component‑and‑connector style, enabling each Processing component to publish its output data trace to downstream components. Resource management is handled through explicit traceability links (originates‑from associations) that allow transitive provenance tracking. Coordination is achieved by a central orchestration service that schedules model execution and ensures the consistent integration of newly generated friction models into the Twin."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Model fidelity and validity are addressed through traceability and verification of the transformation chain linking high‑level SysML specifications to executable simulation models (e.g., Simulink) and to data‑driven components. The documents stress that the reliability of a digital shadow depends on the correctness of its underlying models and the applied data transformations, therefore verification methods are applied to ensure model‑to‑model consistency. Quality assurance includes checking the integrity of contextual data traces, maintaining provenance information, and employing model‑based verification techniques to detect and correct errors introduced during abstraction or code generation. While explicit uncertainty quantification is not detailed, the emphasis on correctness, traceability, and verification constitutes the primary strategy for managing model fidelity and validity."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Data exchange between the physical asset and the digital twin is realized using the MQTT protocol (publish‑subscribe messaging)."
]

instance horizontal_integration : DTDFVocab:HoriIntegration [
    base:desc "Interoperability is realised through the implementation of Asset Administration Shells (AAS) for the Twin, providing a standardised information model. Data exchange with the physical controller (Siemens SINUMERIK 840D) and with external engineering tools (MathWorks MATLAB/Simulink) is performed via MQTT streams, enabling publish/subscribe communication. The Twin therefore depends on the external controller for real‑time sensor data and on Simulink for simulation models, following a loosely‑coupled integration pattern based on open‑source IoT messaging."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "The DT development follows Model‑Based Systems Engineering (MBSE) practices and adopts established modeling standards such as SysML for requirements, functional, logical and physical architecture definition, and architecture description languages (ACME, AADL, MontiArc) for component‑connector models. These standards provide a common syntax and semantics for model exchange, but the documents do not specify any certification, compliance frameworks, or additional interoperability standards beyond the cited modeling languages."
]
